const W=Math.min(innerWidth,480),H=innerHeight,TILE=52;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x0e1a2a);this.x=0;this.y=0;this.goal=[7,6];this.blocks={'3,2':1,'3,3':1,'4,3':1,'5,3':1};this.c=this.input.keyboard.createCursorKeys();this.r=this.input.keyboard.addKey('R');this.draw();}slide(dx,dy){let nx=this.x,ny=this.y;while(true){const tx=nx+dx,ty=ny+dy;if(tx<0||ty<0||tx>7||ty>6||this.blocks[`${tx},${ty}`])break;nx=tx;ny=ty;}this.x=nx;this.y=ny;this.draw();if(this.x===this.goal[0]&&this.y===this.goal[1])this.end=true;}draw(){if(this.g)this.g.clear();else this.g=this.add.graphics();for(let y=0;y<=6;y++)for(let x=0;x<=7;x++){this.g.lineStyle(1,0x3b82f6,.2).strokeRect(30+x*TILE,80+y*TILE,TILE,TILE);if(this.blocks[`${x},${y}`])this.g.fillStyle(0x334155).fillRect(32+x*TILE,82+y*TILE,TILE-4,TILE-4);}this.g.fillStyle(0x22c55e).fillRect(30+this.goal[0]*TILE+10,80+this.goal[1]*TILE+10,TILE-20,TILE-20);this.g.fillStyle(0xfef08a).fillRect(30+this.x*TILE+12,80+this.y*TILE+12,TILE-24,TILE-24);if(this.end)this.add.text(W/2,40,'CLEAR R').setOrigin(.5);}update(){if(this.r.isDown)this.scene.restart();if(this.end)return;if(Phaser.Input.Keyboard.JustDown(this.c.left))this.slide(-1,0);if(Phaser.Input.Keyboard.JustDown(this.c.right))this.slide(1,0);if(Phaser.Input.Keyboard.JustDown(this.c.up))this.slide(0,-1);if(Phaser.Input.Keyboard.JustDown(this.c.down))this.slide(0,1);}}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,scene:[S]});
